// Timer-triggered function for batch processing
// host.json should set: "functionTimeout": "00:10:00"
app.timer('batchDataProcessor', {
    schedule: '0 */30 * * * *', // Every 30 minutes
    runOnStartup: false,
    handler: async (myTimer, context) => {
        validateConfig();

        const processor = new BatchProcessor(context);
        const jobId = `batch-job-${new Date().toISOString().split('T')[0]}`;

        try {
            context.log(`Starting batch processing job: ${jobId}`);

            // Load checkpoint if resuming
            const existingCheckpoint = await processor.loadCheckpoint(jobId);
            const continuationState = existingCheckpoint || {
                continuationToken: null,
                processedCount: 0,
                lastCheckpoint: null,
            };

            if (existingCheckpoint) {
                context.log(
                    `Resuming from checkpoint: processed=${existingCheckpoint.processedCount}, ` +
                    `lastCheckpoint=${existingCheckpoint.lastCheckpoint}`
                );
            }

            const result = await processor.fetchAndProcessBatches(null, continuationState);

            // Save checkpoint for resumption
            await processor.saveCheckpoint(jobId, continuationState);

            const summary = {
                jobId,
                processedCount: processor.processedCount,
                errorCount: processor.errorCount,
                elapsedMs: processor.elapsedMs,
                completed: result.completed && !result.timedOut,
                timedOut: result.timedOut,
                hasContinuation: !!continuationState.continuationToken,
            };

            context.log(`Batch processing summary: ${JSON.stringify(summary)}`);

            if (result.timedOut) {
                context.warn('Processing timed out - will resume on next trigger');
            }

        } catch (error) {
            context.error(`Batch processing failed: ${error.message}`);
            // Don't expose internal error details
            throw new Error('Batch processing encountered an unrecoverable error');
        } finally {
            processor.dispose();
        }
    },
});

